  const rates = new Map<string, Map<string, ExchangeRate>>();
  const entries: JournalEntry[] = [];
  const accountLines = new Map<string, JournalLine[]>();

  const round = (value: number) => Math.round(value * 10000) / 10000;

  const roundBankers = (num: number): number => {
    const factor = 10000;
    const scaled = num * factor;
    const floored = Math.floor(scaled);
    const fractional = scaled - floored;

    if (fractional < 0.5) return floored / factor;
    if (fractional > 0.5) return (floored + 1) / factor;
    return (floored % 2 === 0 ? floored : floored + 1) / factor;
  };

  const getOrSetRateMap = (from: string): Map<string, ExchangeRate> => {
    if (!rates.has(from)) {
      rates.set(from, new Map());
    }
    return rates.get(from)!;
  };

  const findRate = (from: string, to: string, atTime: number): Effect.Effect<ExchangeRate, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (from === to) {
        return { from, to, rate: 1, timestamp: atTime };
      }

      const fromMap = rates.get(from);
      if (fromMap?.has(to)) {
        const rate = fromMap.get(to)!;
        if (atTime - rate.timestamp <= config.staleRateThresholdMs) {
