      try {
        const exit = Effect.runSyncExit

(balanceEffect);
        if (Exit.isFailure(exit)) {
          const cause = Cause.squash(exit.cause);
          if (cause instanceof Error) throw new LedgerError(cause.message);
          throw new LedgerError("Failed to balance entry");
