      const isBalanced = Math.abs(totalAssets - (totalLiabilities + totalEquity)) <= 0.01;
      return {
        assets,
        liabilities,
        equity,
        totalAssets,
        totalLiabilities,
        totalEquity,
        isBalanced: isBalanced && !hasStaleRate,
