```typescript
import { Effect, Exit, Cause, Data } from "effect";

export type AccountType = 'asset' | 'liability' | 'equity' | 'revenue' | 'expense';

export interface Account {
  id: string;
  name: string;
  type: AccountType;
  currency: string;
}

export interface JournalEntry {
  id: string;
  description: string;
  timestamp: number;
  lines: JournalLine[];
}

export interface JournalLine {
  accountId: string;
  amount: number;
  currency: string;
}

export interface ExchangeRate {
  from: string;
  to: string;
  rate: number;
  timestamp: number;
}

export interface BalanceSheet {
  assets: { accountId: string; balance: number; currency: string }[];
  liabilities: { accountId: string; balance: number; currency: string }[];
  equity: { accountId: string; balance: number; currency: string }[];
  totalAssets: number;
  totalLiabilities: number;
  totalEquity: number;
  isBalanced: boolean;
}

export class LedgerError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "LedgerError";
  }
}

class InternalLedgerError extends Data.TaggedError("InternalLedgerError")<{
  message: string;
}> {}

function roundAmount(amount: number): number {
  return Number(amount.toFixed(4));
}

export function createLedger(config: {
  reportingCurrency: string;
  staleRateThresholdMs: number;
}) {
  // Validation
  if (config.staleRateThresholdMs <= 0) {
    throw new Error("staleRateThresholdMs must be > 0");
  }
  if (!config.reportingCurrency || config.reportingCurrency.trim() === "") {
    throw new Error("reportingCurrency must be non-empty");
  }

  const accounts = new Map<string, Account>();
  const rates = new Map<string, ExchangeRate>();
  const entries: JournalEntry[] = [];
  const accountEntries = new Map<string, JournalEntry[]>();

  const createAccountImpl = (account: Account): Effect.Effect<void, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (!account.id || account.id.trim() === "") {
        yield* Effect.fail(new InternalLedgerError({ message: "Account ID cannot be empty" }));
      }
      if (!account.currency || account.currency.trim() === "") {
        yield* Effect.fail(new InternalLedgerError({ message: "Currency cannot be empty" }));
      }
      if (accounts.has(account.id)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${account.id} already exists` }));
      }
      accounts.set(account.id, account);
    });
  };

  const setRateImpl = (rate: ExchangeRate): Effect.Effect<void, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (rate.rate <= 0) {
        yield* Effect.fail(new InternalLedgerError({ message: "Exchange rate must be > 0" }));
      }
      if (!rate.from || !rate.to || rate.from.trim() === "" || rate.to.trim() === "") {
        yield* Effect.fail(new InternalLedgerError({ message: "Currency codes cannot be empty" }));
      }
      const key = `${rate.from}:${rate.to}`;
      rates.set(key, rate);
    });
  };

  const getRateImpl = (from: string, to: string): ExchangeRate | null => {
    if (from === to) {
      return {
        from,
        to,
        rate: 1,
        timestamp: Date.now(),
      };
    }
    const directKey = `${from}:${to}`;
    const direct = rates.get(directKey);
    if (direct) return direct;

    const inverseKey = `${to}:${from}`;
    const inverse = rates.get(inverseKey);
    if (inverse) {
      return {
        from,
        to,
        rate: roundAmount(1 / inverse.rate),
        timestamp: inverse.timestamp,
      };
    }

    return null;
  };

  const isRateStaleImpl = (rate: ExchangeRate | null, entryTimestamp: number): boolean => {
    if (!rate) return true;
    return entryTimestamp - rate.timestamp > config.staleRateThresholdMs;
  };

  const convertAmountImpl = (
    amount: number,
    fromCurrency: string,
    toCurrency: string,
    entryTimestamp: number
  ): Effect.Effect<number, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (fromCurrency === toCurrency) {
        return roundAmount(amount);
      }
      const rate = getRateImpl(fromCurrency, toCurrency);
      if (!rate) {
        yield* Effect.fail(new InternalLedgerError({ message: `No rate available for ${fromCurrency} to ${toCurrency}` }));
      }
      if (isRateStaleImpl(rate, entryTimestamp)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Rate ${fromCurrency} to ${toCurrency} is stale` }));
      }
      return roundAmount(amount * rate!.rate);
    });
  };

  const postEntryImpl = (entry: Omit<JournalEntry, 'id'>): Effect.Effect<string, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (!entry.lines || entry.lines.length < 2) {
        yield* Effect.fail(new InternalLedgerError({ message: "Entry must have at least 2 lines" }));
      }

      for (const line of entry.lines) {
        if (!accounts.has(line.accountId)) {
          yield* Effect.fail(new InternalLedgerError({ message: `Account ${line.accountId} does not exist` }));
        }
      }

      let totalInReporting = 0;
      for (const line of entry.lines) {
        const convertedAmount = yield* convertAmountImpl(
          line.amount,
          line.currency,
          config.reportingCurrency,
          entry.timestamp
        );
        totalInReporting = roundAmount(totalInReporting + convertedAmount);
      }

      if (Math.abs(totalInReporting) > 0.01) {
        yield* Effect.fail(new InternalLedgerError({ message: "Entry is not balanced" }));
      }

      const entryId = `entry-${Date.now()}-${Math.random().toString(36).substring(2, 11)}`;
      const newEntry: JournalEntry = {
        id: entryId,
        description: entry.description,
        timestamp: entry.timestamp,
        lines: entry.lines,
      };

      entries.push(newEntry);
      for (const line of entry.lines) {
        if (!accountEntries.has(line.accountId)) {
          accountEntries.set(line.accountId, []);
        }
        accountEntries.get(line.accountId)!.push(newEntry);
      }

      return entryId;
    });
  };

  const getBalanceImpl = (accountId: string): Effect.Effect<number, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (!accounts.has(accountId)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${accountId} does not exist` }));
      }
      let balance = 0;
      const accountEnts = accountEntries.get(accountId) || [];
      for (const ent of accountEnts) {
        for (const line of ent.lines) {
          if (line.accountId === accountId) {
            balance = roundAmount(balance + line.amount);
          }
        }
      }
      return balance;
    });
  };

  const getBalanceInImpl = (
    accountId: string,
    currency: string,
    atTime: number
  ): Effect.Effect<number, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (!accounts.has(accountId)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${accountId} does not exist` }));
      }
      const account = accounts.get(accountId)!;
      let nativeBalance = 0;
      const accountEnts = accountEntries.get(accountId) || [];
      for (const ent of accountEnts) {
        if (ent.timestamp > atTime) continue;
        for (const line of ent.lines) {
          if (line.accountId === accountId) {
            nativeBalance = roundAmount(nativeBalance + line.amount);
          }
        }
      }

      if (account.currency === currency) {
        return nativeBalance;
      }

      const convertedAmount = yield* convertAmountImpl(
        nativeBalance,
        account.currency,
        currency,
        atTime
      );
      return convertedAmount;
    });
  };

  const balanceSheetImpl = (atTime: number): Effect.Effect<BalanceSheet, InternalLedgerError> => {
    return Effect.gen(function* () {
      const assets: { accountId: string; balance: number; currency: string }[] = [];
      const liabilities: { accountId: string; balance: number; currency: string }[] = [];
      const equity: { accountId: string; balance: number; currency: string }[] = [];

      let totalAssets = 0;
      let totalLiabilities = 0;
      let totalEquity = 0;
      let isBalanced = true;

      for (const [accountId, account] of accounts) {
        let nativeBalance = 0;
        const accountEnts = accountEntries.get(accountId) || [];
        for (const ent of accountEnts) {
          if (ent.timestamp > atTime) continue;
          for (const line of ent.lines) {
            if (line.accountId === accountId) {
              nativeBalance = roundAmount(nativeBalance + line.amount);
            }
          }
        }

        let balanceInReporting = nativeBalance;
        if (account.currency !== config.reportingCurrency) {
          const rate = getRateImpl(account.currency, config.reportingCurrency);
          if (!rate || isRateStaleImpl(rate, atTime)) {
            isBalanced = false;
          }
          if (rate) {
            balanceInReporting = roundAmount(nativeBalance * rate.rate);
          }
        }

        const item = { accountId, balance: nativeBalance, currency: account.currency };

        if (account.type === 'asset') {
          assets.push(item);
          totalAssets = roundAmount(totalAssets + balanceInReporting);
        } else if (account.type === 'liability') {
          liabilities.push(item);
          totalLiabilities = roundAmount(totalLiabilities - balanceInReporting);
        } else if (account.type === 'equity') {
          equity.push(item);
          totalEquity = roundAmount(totalEquity - balanceInReporting);
        }
      }

      const isBalancedCheck = Math.abs(roundAmount(totalAssets - (totalLiabilities + totalEquity))) < 0.01;

      return {
        assets,
        liabilities,
        equity,
        totalAssets,
        totalLiabilities,
        totalEquity,
        isBalanced: isBalancedCheck && isBalanced,
      };
    });
  };

  const getEntriesImpl = (accountId: string): Effect.Effect<JournalEntry[], InternalLedgerError> => {
    return Effect.gen(function* () {
      if (!accounts.has(accountId)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${accountId} does not exist` }));
      }
      return accountEntries.get(accountId) || [];
    });
  };

  const settleImpl = (
    liabilityAccountId: string,
    assetAccountId: string,
    amount: number,
    timestamp: number
  ): Effect.Effect<string, InternalLedgerError> => {
    return Effect.gen(function* () {
      if (amount <= 0) {
        yield* Effect.fail(new InternalLedgerError({ message: "Settlement amount must be > 0" }));
      }

      if (!accounts.has(liabilityAccountId)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${liabilityAccountId} does not exist` }));
      }
      if (!accounts.has(assetAccountId)) {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${assetAccountId} does not exist` }));
      }

      const liabilityAccount = accounts.get(liabilityAccountId)!;
      const assetAccount = accounts.get(assetAccountId)!;

      if (liabilityAccount.type !== 'liability') {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${liabilityAccountId} is not a liability` }));
      }
      if (assetAccount.type !== 'asset') {
        yield* Effect.fail(new InternalLedgerError({ message: `Account ${assetAccountId} is not an asset` }));
      }

      let settlementAmount = amount;
      if (liabilityAccount.currency !== assetAccount.currency) {
        settlementAmount = yield* convertAmountImpl(
          amount,
          assetAccount.currency,
          liabilityAccount.currency,
          timestamp
        );
      }

      const settlementEntry: Omit<JournalEntry, 'id'> = {
        description: `Settlement: ${assetAccountId} -> ${liabilityAccountId}`,
        timestamp,
        lines: [
          {
            accountId: liabilityAccountId,
            amount: settlementAmount,
